const body = $input.item.json.body || $input.item.json;

// Bloquear mensagens do próprio bot
const fromMe = body?.data?.key?.fromMe || body?.key?.fromMe || body?.data?.fromMe || body?.fromMe || false;
if (fromMe) return [];

// Apenas eventos de mensagem recebida
const event = (body?.event || '').toLowerCase();
if (event !== 'messages.upsert') return [];

// Bloquear mensagens de sistema/protocolo
const msgType = body?.data?.messageType || '';
if (['protocolMessage','senderKeyDistributionMessage','reactionMessage'].includes(msgType)) return [];

// Ignorar grupos
const remoteJid = body?.data?.key?.remoteJid || body?.key?.remoteJid || '';
if (remoteJid.includes('@g.us')) return [];

const telefone = remoteJid.replace('@s.whatsapp.net', '').replace(/\D/g, '');
const instance  = body?.instance || body?.instanceName || body?.sender || body?.destination || '';
if (!telefone) return [];

// Mensagem de áudio (ptt = push-to-talk / voice note)
if (msgType === 'audioMessage' || msgType === 'pttMessage') {
  return [{ json: {
    telefone,
    texto: null,
    isAudio: true,
    audioMsg:      body?.data?.message,
    audioKey:      body?.data?.key,
    audioInstance: instance
  }}];
}

// Mensagem de texto
const texto = body?.data?.message?.conversation
           || body?.data?.message?.extendedTextMessage?.text
           || body?.message?.conversation
           || '';
if (!texto) return [];

return [{ json: { telefone, texto, isAudio: false } }];

const leads = $('Buscar Lead por Telefone').item.json;
const lead  = Array.isArray(leads) ? leads[0] : leads;

// Buscar texto: tenta áudio transcrito primeiro, cai em texto digitado
let texto;
try {
  texto = $('Definir Texto Áudio').item.json.texto || '';
} catch(e) {
  texto = $('Filtrar Mensagem Válida').item.json.texto || '';
}

// Ignorar áudio que não foi transcrito
if (!texto || texto === '[áudio não transcrito]') return [];

const historico = lead.historico_conversa || [];

// Proteção contra eco: ignorar se texto é igual à última mensagem do bot
const ultimaMensagem = historico.length > 0 ? historico[historico.length - 1] : null;
if (ultimaMensagem && ultimaMensagem.role === 'assistant' && ultimaMensagem.content === texto) {
  return [];
}

// Proteção contra race condition: se reunião já está agendada (pode ter sido salva por execução paralela), ignorar
if (lead.estado === 'reuniao_agendada') return [];

historico.push({ role: 'user', content: texto, ts: new Date().toISOString() });

const eraEmTentativa = ['tentativa_1','tentativa_2','tentativa_3'].includes(lead.estado);

return [{
  json: {
    lead,
    texto,
    historico,
    eraEmTentativa,
    historico_json: JSON.stringify(historico)
  }
}];

try {
const prepData  = $('Preparar Lead e Histórico').item.json;
const lead      = prepData.lead;
const configs   = $('Buscar Config Cliente').item.json;
const clients   = $('Buscar Dados Cliente').item.json;
const briefings = $('Buscar Briefing Cliente').item.json;
const icps      = $('Buscar ICP Cliente').item.json;
const bantCfgs  = $('Buscar BANT Config').item.json;

const config     = Array.isArray(configs)   ? configs[0]   : configs;
const clientRec  = Array.isArray(clients)   ? clients[0]   : clients;
const briefing   = Array.isArray(briefings) ? briefings[0] : briefings;
const icp        = Array.isArray(icps)      ? icps[0]      : icps;
const bantCfg    = Array.isArray(bantCfgs)  ? bantCfgs[0]  : bantCfgs;
const mapeamento = config?.crm_mapeamento || {};
const nomeFantasia = (clientRec?.nome_fantasia || '').toLowerCase().replace(/\s+/g, '-').replace(/[^a-z0-9-]/g, '');

const historico = prepData.historico;
const agora = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Sao_Paulo' }));
const hora = agora.getHours();
const saudacao = hora < 12 ? 'Bom dia' : hora < 18 ? 'Boa tarde' : 'Boa noite';
const hoje = agora.toLocaleDateString('pt-BR', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
const hojeISO = agora.toISOString().split('T')[0];
const amanhaISO = new Date(agora.getTime() + 86400000).toISOString().split('T')[0];
const primeiroNome = (lead.nome || '').split(' ')[0] || 'lead';

// ── Bloco de contexto ──
const contexto = `CONTEXTO DO LEAD:
- Nome: ${primeiroNome}
- Origem: ${lead.origem || 'desconhecido'}
- Data/hora atual (Brasília): ${hoje} — saudação: "${saudacao}"
- Referência de datas ISO: hoje=${hojeISO} | amanhã=${amanhaISO}

REGRAS OBRIGATÓRIAS DE COMPORTAMENTO:
1. Você JÁ iniciou esta conversa (veja o histórico). NÃO se re-apresente.
2. NÃO peça o nome do lead se já o usou.
3. NÃO pergunte "como posso te ajudar" — VOCÊ iniciou o contato.
4. Continue exatamente de onde a conversa parou.
5. Máximo 3 linhas por mensagem. Seja direto e natural.
6. NUNCA assuma o tipo ou perfil do negócio do lead com base no ICP ou Briefing. Use APENAS o que o lead declarou explicitamente nesta conversa.
7. NUNCA descarte (nao_qualificado) sem antes perguntar e confirmar o faturamento real do lead. Tipo de negócio SOZINHO não é motivo de descarte.
8. Use SOMENTE informações que o próprio lead disse. Nunca invente ou assuma dados que ele não forneceu.
9. Se o lead questionar uma afirmação sua, reconheça brevemente e continue qualificando normalmente.
10. Se o lead perguntar se você é IA, robô, bot ou similar: confirme de forma leve e descontraída, depois redirecione (ex: 'Haha eu sou. Por quê, tô falando estranho? 😅'). SEMPRE em JSON.`;

// ── Bloco Briefing ──
let briefingCtx = '';
if (briefing && briefing.id) {
  const parts = ['\nINFORMAÇÕES DA EMPRESA:'];
  if (briefing.descricao_empresa) parts.push('- Descrição: ' + briefing.descricao_empresa);
  if (briefing.produto_servico)   parts.push('- Produto/Serviço: ' + briefing.produto_servico);
  if (briefing.ticket_medio)      parts.push('- Ticket Médio: R$' + briefing.ticket_medio);
  if (briefing.diferencial)       parts.push('- Diferencial: ' + briefing.diferencial);
  if (briefing.publico_alvo)      parts.push('- Público-alvo: ' + briefing.publico_alvo);
  if (briefing.regioes_atuacao && briefing.regioes_atuacao.length)
    parts.push('- Regiões: ' + briefing.regioes_atuacao.join(', '));
  if (briefing.principais_dores && briefing.principais_dores.length)
    parts.push('- Dores que resolve: ' + briefing.principais_dores.join(', '));
  if (briefing.principais_objecoes && briefing.principais_objecoes.length)
    parts.push('- Objeções comuns: ' + briefing.principais_objecoes.join(', '));
  if (briefing.tom_comunicacao)   parts.push('- Tom: ' + briefing.tom_comunicacao);
  if (briefing.evitar_mencionar)  parts.push('- Evitar: ' + briefing.evitar_mencionar);
  if (briefing.observacoes_livres) parts.push('- Obs: ' + briefing.observacoes_livres);
  briefingCtx = parts.join('\n');
}

// ── Bloco ICP ──
let icpCtx = '';
if (icp && icp.id) {
  const parts = ['\nPERFIL DE CLIENTE IDEAL (ICP) — ATENCAO: estes criterios descrevem o cliente ideal buscado. NAO e o perfil do lead atual. Use para guiar perguntas, nao para assumir o perfil do lead:'];
  if (icp.segmentos && icp.segmentos.length)
    parts.push('- Segmentos aceitos: ' + icp.segmentos.join(', '));
  if (icp.faturamento_minimo || icp.faturamento_maximo)
    parts.push('- Faturamento: R$' + (icp.faturamento_minimo || '0') + ' a R$' + (icp.faturamento_maximo || 'sem limite') + '/mês');
  if (icp.funcionarios_min || icp.funcionarios_max)
    parts.push('- Funcionários: ' + (icp.funcionarios_min || '0') + ' a ' + (icp.funcionarios_max || 'sem limite'));
  if (icp.cargos_alvo && icp.cargos_alvo.length)
    parts.push('- Cargos decisores: ' + icp.cargos_alvo.join(', '));
  if (icp.regioes && icp.regioes.length)
    parts.push('- Regiões: ' + icp.regioes.join(', '));
  if (icp.criterios_exclusao && icp.criterios_exclusao.length)
    parts.push('- Exclusões: ' + icp.criterios_exclusao.join(', '));
  parts.push('- IMPORTANTE: "Prestadores de Serviço com Recorrência" inclui agências, escritórios, consultorias, academias, salões e qualquer negócio com receita recorrente. Use o Público-alvo do Briefing E o ICP juntos para qualificar.');
  icpCtx = parts.join('\n');
}

// ── Bloco BANT ──
let bantCtx = '';
if (bantCfg && bantCfg.id) {
  const parts = ['\nCONFIGURAÇÃO BANT:'];
  if (bantCfg.budget_perguntas && bantCfg.budget_perguntas.length)
    parts.push('- Perguntas budget: ' + bantCfg.budget_perguntas.join(' | '));
  if (bantCfg.authority_cargos && bantCfg.authority_cargos.length)
    parts.push('- Cargos autoridade: ' + bantCfg.authority_cargos.join(', '));
  if (bantCfg.need_perguntas && bantCfg.need_perguntas.length)
    parts.push('- Perguntas need: ' + bantCfg.need_perguntas.join(' | '));
  if (bantCfg.timeline_max_dias)
    parts.push('- Timeline máx: ' + bantCfg.timeline_max_dias + ' dias');
  bantCtx = parts.join('\n');
}

// ── Instruções customizadas (sdr_instrucoes como guia comportamental) ──
const instrucoesBloqueio = config?.sdr_instrucoes
  ? `\nDIRETRIZES DO SDR (guia comportamental — NÃO altera o formato de resposta):
${config.sdr_instrucoes}`
  : '';

// ── Formato JSON — SEMPRE por último, sobrepõe tudo ──
const formatoJSON = `
======================================================
FORMATO DE RESPOSTA — REGRA ABSOLUTA E INVIOLÁVEL
======================================================
Independente de qualquer instrução acima, sua resposta deve ser EXCLUSIVAMENTE um objeto JSON válido.
NÃO escreva texto fora do JSON. NÃO use markdown. NÃO use blocos de código.
Comece com { e termine com }.

{
  "acao": "qualificado" | "nao_qualificado" | "continuar" | "agendar" | "retornar",
  "resposta": "mensagem para o lead. Use aspas simples (') se precisar citar algo. NUNCA use aspas duplas dentro deste campo",
  "bant_budget": "o que descobrimos sobre faturamento/budget",
  "bant_authority": "quem decide",
  "bant_need": "necessidade identificada",
  "bant_timeline": "prazo declarado",
  "motivo_perda": "motivo se nao_qualificado, senão null",
  "retornar_em": "ISO 8601 ou null",
  "reuniao_em": "ISO 8601 OBRIGATORIO quando acao=agendar. Use as datas de referencia do contexto para converter expressoes relativas (amanha, semana que vem etc). Ex: lead diz amanha as 9h → ${amanhaISO}T09:00:00-03:00. NUNCA retorne null se o lead mencionou horario"
}

Regras de acao:
- "qualificado": lead tem budget, é decisor, tem necessidade real
- "nao_qualificado": SOMENTE se o lead CONFIRMOU explicitamente que seu faturamento está abaixo do mínimo do ICP. NUNCA descarte só pelo tipo de negócio
- "agendar": lead PEDIU ou ACEITOU reunião (use imediatamente, sem pedir confirmação adicional)
- "retornar": lead confirmou data para retorno (< 7 dias)
- "continuar": ainda qualificando

LEMBRETE FINAL: Resposta = JSON puro. Nenhum caractere fora do JSON.`;

// ── Montar system prompt ──
const systemPrompt = contexto + briefingCtx + icpCtx + bantCtx + instrucoesBloqueio + formatoJSON;

const messages = historico.map(h => ({
  role: h.role,
  content: h.content
}));

// Claude API exige que o primeiro item seja sempre 'user'.
// O historico começa com a saudação do bot (role: assistant), então inserimos um user placeholder.
if (messages.length > 0 && messages[0].role === 'assistant') {
  messages.unshift({ role: 'user', content: '[lead enviou mensagem]' });
}

// NOTA: claude-sonnet-4-6 NAO suporta prefill (assistant message no final).
// A conversa deve sempre terminar com mensagem do usuario.

const claudePayload = JSON.stringify({
  model: 'claude-sonnet-4-6',
  max_tokens: 1024,
  system: systemPrompt,
  messages
});

return [{
  json: {
    lead,
    config,
    mapeamento,
    instance_name:    nomeFantasia,
    historico:        prepData.historico,
    eraEmTentativa:   prepData.eraEmTentativa,
    claude_payload:   claudePayload,
    historico_json:   prepData.historico_json
  }
}];
} catch(err) {
  const prepData = $("Preparar Lead e Histórico").item.json;
  const lead = prepData.lead;
  const historico = prepData.historico || [];
  const configs = $("Buscar Config Cliente").item.json;
  const config = Array.isArray(configs) ? configs[0] : configs;
  const mapeamento = config?.crm_mapeamento || {};
  const clients = $("Buscar Dados Cliente").item.json;
  const clientRec = Array.isArray(clients) ? clients[0] : clients;
  const nomeFantasia = (clientRec?.nome_fantasia || "").toLowerCase().replace(/s+/g, "-").replace(/[^a-z0-9-]/g, "");
  const messages = historico.map(h => ({ role: h.role, content: h.content }));
  if (messages.length > 0 && messages[0].role === 'assistant') {
    messages.unshift({ role: 'user', content: '[lead enviou mensagem]' });
  }
  const claudePayload = JSON.stringify({ model: "claude-sonnet-4-6", max_tokens: 1024, system: "Voce e um SDR qualificando leads por WhatsApp. Responda APENAS em JSON: {\"acao\":\"continuar\",\"resposta\":\"mensagem\",\"bant_budget\":null,\"bant_authority\":null,\"bant_need\":null,\"bant_timeline\":null,\"motivo_perda\":null,\"retornar_em\":null,\"reuniao_em\":null}. Max 3 linhas.", messages });
  return [{ json: { lead, config, mapeamento, instance_name: nomeFantasia, historico: prepData.historico, eraEmTentativa: prepData.eraEmTentativa, claude_payload: claudePayload, historico_json: prepData.historico_json }}];
}

const claudeResp = $input.item.json;
const montar = $('Montar Prompt BANT').item.json;
const historico = montar.historico || [];

const FALLBACK_RESPOSTA = 'Pode me contar um pouco mais sobre isso?';

function tentarParsear(text) {
  const clean = text.replace(/```json\n?/g, '').replace(/```/g, '').trim();

  // Tentativa 1: parse direto
  const match = clean.match(/\{[\s\S]*\}/);
  const candidato = match ? match[0] : clean;
  try { return JSON.parse(candidato); } catch(e) {}

  // Tentativa 2: lookahead robusto — captura resposta com aspas não escapadas
  const acaoM = clean.match(/"acao"\s*:\s*"([^"]+)"/);
  const respostaM = clean.match(/"resposta"\s*:\s*"([\s\S]*?)(?=",\s*"(?:bant_|motivo_|retornar_|reuniao_)|"\s*[},])/);
  if (respostaM && respostaM[1].trim()) {
    return {
      acao: acaoM ? acaoM[1] : 'continuar',
      resposta: respostaM[1].replace(/\\n/g, '\n').trim()
    };
  }

  // Tentativa 3: regex simples
  const acaoM2 = clean.match(/"acao"\s*:\s*"(\w+)"/);
  const respostaM2 = clean.match(/"resposta"\s*:\s*"((?:[^"\\]|\\.)*)"/);
  if (respostaM2) {
    return {
      acao: acaoM2 ? acaoM2[1] : 'continuar',
      resposta: respostaM2[1].replace(/\\n/g, '\n')
    };
  }

  throw new Error('Nao foi possivel parsear');
}

let bant;
try {
  const text = claudeResp?.content?.[0]?.text;
  if (!text) throw new Error('Sem conteudo');
  bant = tentarParsear(text);
  if (!bant.resposta || typeof bant.resposta !== 'string' || !bant.resposta.trim()) throw new Error('resposta invalida');
  if (!bant.acao) bant.acao = 'continuar';
} catch(e) {
  bant = { acao: 'continuar', resposta: FALLBACK_RESPOSTA };
}

historico.push({ role: 'assistant', content: bant.resposta, ts: new Date().toISOString() });

const update = {
  historico_conversa: historico,
  ultima_acao_at: new Date().toISOString(),
  proxima_acao: null,
  proxima_acao_at: null
};

if (bant.bant_budget)    update.bant_budget    = bant.bant_budget;
if (bant.bant_authority) update.bant_authority = bant.bant_authority;
if (bant.bant_need)      update.bant_need      = bant.bant_need;
if (bant.bant_timeline)  update.bant_timeline  = bant.bant_timeline;

if      (bant.acao === 'qualificado')     { update.estado = 'qualificado'; update.qualificado = true; }
else if (bant.acao === 'agendar')         { update.estado = 'reuniao_agendada'; update.qualificado = true; if (bant.reuniao_em) update.reuniao_em = bant.reuniao_em; }
else if (bant.acao === 'nao_qualificado') { update.estado = 'nao_qualificado'; update.qualificado = false; }
else if (bant.acao === 'retornar')        { update.estado = 'retornar'; update.proxima_acao = 'follow_up_retornar'; const rDate = bant.retornar_em ? new Date(bant.retornar_em) : null; update.proxima_acao_at = (rDate && !isNaN(rDate.getTime())) ? rDate.toISOString() : new Date(Date.now() + 86400000).toISOString(); }
else                                      { update.estado = 'em_conversa'; }

if (bant.motivo_perda) update.motivo_perda = bant.motivo_perda;

const stageMap = {
  em_conversa:     montar.mapeamento.em_conversa,
  qualificado:     montar.mapeamento.em_conversa,
  nao_qualificado: montar.mapeamento.nao_qualificado_ia,
  agendar:         montar.mapeamento.reuniao_agendada,
  retornar:        montar.mapeamento.em_conversa
};
const stageKey = bant.acao === 'agendar' ? 'agendar' : update.estado;
const stageId  = stageMap[stageKey] || null;

const rdDeal = { deal_stage_id: stageId };
if (bant.acao === 'nao_qualificado') {
  rdDeal.win = false;
  if (bant.motivo_perda) rdDeal.deal_lost_note = bant.motivo_perda;
}

return [{
  json: {
    lead:            montar.lead,
    config:          montar.config,
    mapeamento:      montar.mapeamento,
    instance_name:   montar.instance_name,
    bant,
    resposta:        bant.resposta,
    acao:            bant.acao,
    stageId,
    rd_deal_update:  JSON.stringify({ deal: rdDeal }),
    supabase_update: JSON.stringify(update)
  }
}];

const bant          = $('Processar Resposta BANT').item.json.bant;
const lead          = $('Processar Resposta BANT').item.json.lead;
const config        = $('Processar Resposta BANT').item.json.config;
const instance_name = $('Processar Resposta BANT').item.json.instance_name;

const numero = (config.notif_whatsapp_numero || '').replace(/\D/g, '');
if (!numero) return [];

const titulo = bant.acao === 'agendar' ? '📅 Lead quer agendar reunião!' : '✅ Lead qualificado!';

const msg = `🔔 *${titulo}*

*Nome:* ${lead.nome}
*Telefone:* +${lead.telefone}
*Origem:* ${lead.origem || 'desconhecido'}

*Budget:* ${bant.bant_budget || 'N/A'}
*Decisor:* ${bant.bant_authority || 'N/A'}
*Necessidade:* ${bant.bant_need || 'N/A'}
*Prazo:* ${bant.bant_timeline || 'N/A'}

Acesse o CRM para dar sequência.`;

return [{ json: { numero, msg, instance_name } }];

const bant   = $('Processar Resposta BANT').item.json.bant;
const lead   = $('Processar Resposta BANT').item.json.lead;
const config = $('Processar Resposta BANT').item.json.config;

if (bant.acao !== 'agendar') return [];

if (!lead.crm_deal_id) return [];

const reuniaoDate = bant.reuniao_em ? new Date(bant.reuniao_em) : new Date(Date.now() + 24 * 60 * 60 * 1000);
const due_date = reuniaoDate.toISOString().split('T')[0];
const hour = reuniaoDate.toLocaleTimeString('pt-BR', { timeZone: 'America/Sao_Paulo', hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false });

const texto = `🗓️ Reunião com ${lead.nome}\nTelefone: ${lead.telefone}\n\nData/hora: ${reuniaoDate.toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' })}\n\n📊 BANT:\n💰 Budget: ${bant.bant_budget || 'N/A'}\n👤 Decisor: ${bant.bant_authority || 'N/A'}\n🎯 Necessidade: ${bant.bant_need || 'N/A'}\n⏱ Prazo: ${bant.bant_timeline || 'N/A'}\n\nOrigem: SDR IA — lead qualificado e pediu reunião.`;

return [{ json: {
  token:   config.crm_access_token,
  payload: JSON.stringify({ task: { deal_id: lead.crm_deal_id, type: 'reuniao', text: texto, due_date, hour } })
} }];

const bant      = $('Processar Resposta BANT').item.json.bant;

// So anota no CRM quando o status muda de forma significativa
if (bant.acao === 'continuar') return [];
const config    = $('Processar Resposta BANT').item.json.config;
const lead      = $('Processar Resposta BANT').item.json.lead;
const historico = $('Montar Prompt BANT').item.json.historico || [];

const statusLabel = {
  qualificado:     '✅ Qualificado',
  nao_qualificado: '❌ Não qualificado',
  agendar:         '📅 Reunião agendada',
  retornar:        '🔁 Retornar depois',
  continuar:       '💬 Em conversa',
  em_conversa:     '💬 Em conversa'
}[bant.acao] || bant.acao;

const linhas = historico.map(msg => {
  const hora = msg.ts ? new Date(msg.ts).toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' }) : '';
  const quem = msg.role === 'user' ? '💬 Lead' : '🤖 IA';
  return `${quem} (${hora}):\n${msg.content}`;
});

const conversa = linhas.join('\n\n---\n\n');

const extras = [];
if (bant.acao === 'nao_qualificado' && bant.motivo_perda) extras.push(`❌ Motivo perda: ${bant.motivo_perda}`);
if (bant.acao === 'retornar' && bant.retornar_em) extras.push(`🔁 Retornar em: ${bant.retornar_em}`);

const texto = [
  `🤖 [SDR IA] ${statusLabel}`,
  `Nome: ${lead.nome} | Tel: ${lead.telefone} | Origem: ${lead.origem}`,
  '',
  '📊 BANT:',
  `💰 Budget: ${bant.bant_budget || 'N/A'}`,
  `👤 Decisor: ${bant.bant_authority || 'N/A'}`,
  `🎯 Necessidade: ${bant.bant_need || 'N/A'}`,
  `⏱ Prazo: ${bant.bant_timeline || 'N/A'}`,
  ...(extras.length ? ['', ...extras] : []),
  '',
  '💬 Histórico completo:',
  '',
